var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"오호, 이게 그 로터스의 시니어가 만든 장치란 말이지?","JPN":"ほお、これがあのロータスのシニアが作った装置か。","ENG":"Oho, so this is the device made by the Lotus's Senior?","TWN":"哦哦，這就是洛德斯的Senior製作的裝置嗎？"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"인플로전 리액터? 이거 설마 이터니움 드라이브를 바탕으로 만든 거야?","JPN":"インプロージョン・リアクター？　まさかエタニウムドライブを基に作ったのか？","ENG":"An implosion reactor? Is this based on the Eternium Drive?","TWN":"內爆反應爐？這難不成是以永恆之金引擎為基礎製造的？"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"하, 천재라는 소문이 사실이었군. 이터니움 드라이브를 모사하다니.","JPN":"ははっ、天才っていう噂は本当だったんだな。エタニウムドライブを真似るとは。","ENG":"Ha, the rumor about you being a genius was true. You replicated the Eternium Drive.","TWN":"哈，竟然能模仿永恆之金引擎，妳果然跟傳聞說的一樣是天才。"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"여, 역시! 기계수집가, 당신이라면 알아줄 줄 알았어!","JPN":"さ、さすが！　機械収集家、あなたなら分かってくれると思った！","ENG":"I-I knew it! Machine Collector, I figured you would notice!","TWN":" 我、我就知道！機械收藏家，果然你會看得懂！"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"단번에 선로전환기가 이터니움 드라이브를 참고해서 만들었다는 걸 알아차렸잖아?","JPN":"線路転換器がエタニウムドライブを参考にして作られたものだってこと、一目でわかってくれたのね！","ENG":"You realized right away that the Track Switcher referenced the Eternium Drive, right?","TWN":"你一眼就認出線路轉換器是參考永恆之金引擎製成的吧？"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"저 멍청이들은 내가 백날 설명해 줘도 못 알아먹겠다는 표정이었다고!","JPN":"あのバカたちは、いくら私が説明しても理解できないって顔してたのに！","ENG":"Those idiots looked lost no matter how many times I explained it!","TWN":"就算我解釋一百遍，那些笨蛋也是一臉聽不懂的表情！"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"이런 천재를 이런 망령 들린 도시에 처박아놓고 잡무만 시키고 있었다니…….","JPN":"これほどの天才を、こんな亡霊都市にぶち込んで雑務ばかりやらせていたとは……","ENG":"To lock a genius like this in a ghost-ridden city and dump only chores on her...","TWN":"竟然把我這種天才關在鬧鬼的城市，還只讓我做雜務……"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"공학의 길을 걷는 선배로서, 후배의 처지가 무척 안타깝지 않아?","JPN":"工学の道を歩む先輩としては、後輩のこの境遇を可哀想だとは思わないか？","ENG":"As a senior in engineering, isn't it painful to see a junior stuck like this?","TWN":"身為走在工學路上的前輩，你不覺得後輩的處境很可憐嗎？"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"선배……?","JPN":"先輩……？","ENG":"Senior...?","TWN":"前輩……？"},"stage":{"bg":"OMEN_LOTUS_02","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"인간의 자질구레한 일에는 관심 없다.","JPN":"人間の些細なことに興味はない。","ENG":"I have no interest in human trifles.","TWN":"我對人類那些瑣碎的事沒興趣。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_TOUCH"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"나의 끝없는 진화에만 관심이 있을 뿐.","JPN":"私が興味を持つのは、己の果てない進化のみだ。","ENG":"I care only for my endless evolution.","TWN":"我只在意自己無止境的進化。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"시니어, 내 <color=#ffd34c>콜로서스 베이스</color>에서 선로전환기 제작을 완료했다.","JPN":"シニア、私の<color=#ffd34c>コロッサスベース</color>で線路転換器の製作を完了した。","ENG":"Senior, we completed the Track Switcher at my <color=#ffd34c>Colossus Base</color>.","TWN":"Senior，我在我的<color=#ffd34c>巨像基地</color>完成線路轉換器了。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"코, 콜로서스 베이스라고?","JPN":"コ、コロッサスベース？","ENG":"C-Colossus Base?","TWN":"巨、巨像基地？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"분명 신지아 회장은 알파트릭스의 소유인 것처럼 말했는데?","JPN":"ヒメノ会長は確か、アルファトリックスが所有しているみたいに言っていたけど？","ENG":"President Shin Jia made it sound like Alphatrix owned that.","TWN":"明明沈佳會長說那是阿爾法崔克斯的資產？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"놈들의 오비탈 베이스는 내가 차지했다.","JPN":"やつらのオービタルベースは私がいただいた。","ENG":"I seized their Orbital Base.","TWN":"他們的軌道基地已經被我佔領了。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"클리포트 게임에 참전해 너흴 도운 건 그걸 얻기 위함이었으니.","JPN":"クリフォトゲームに参戦してお前らに協力したのは、それを得るためだったからな。","ENG":"I joined the Qliphoth Game and aided you in order to obtain it.","TWN":"我會參加逆卡巴拉遊戲並協助你們，就是為了得到它。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"……스캐빈저의 대장이라고 했지?","JPN":"……スカベンジャーのボス。","ENG":"...You're the leader of Scavengers, right?","TWN":"……你就是清道夫的隊長吧？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"저 잘빠진 직선, 투박한 동체! 육중한 무기!","JPN":"そのまっすぐ伸びたラインに、ごつい胴体、重量感溢れる武器！","ENG":"Those clean straight lines, that rugged body, the heavy weapons!","TWN":"那筆直的線條、厚實的機體！滿載的武裝！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L29_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하, 한 번만 만져봐도 돼?!","JPN":"い、一回だけ触ってみてもいい？","ENG":"C-can I touch it just once?!","TWN":"能、能不能讓我摸一次？！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"당신 말은 뒷전인 것 같은데?","JPN":"お前の話は耳に入ってないようだな。","ENG":"She seems to be ignoring what you are saying.","TWN":"她好像完全沒在聽你說話耶？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그리고 그 목소리 말이야…….","JPN":"あと、その声なんだけど……","ENG":"And that voice...","TWN":"而且這個聲音……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"그럼 이졸데, 이거 하나만 기억해 줄 수 있니?","JPN":"じゃあイゾルデ、これだけは覚えていてくれる？","ENG":"Isolde, could you remember this one thing for me?","TWN":"伊索德，妳能幫我記住一句話嗎？"},"stage":{"bg":"OMEN_LOTUS_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"이 말을 간직하고 있다가, 꼭 세상을 지켜주길 바라.","JPN":"この言葉を忘れないで、世界を守ってね。","ENG":"Hold on to these words and use them to protect the world.","TWN":"希望妳能把它放在心裡，總有一天能守護世界。"},"stage":{"bg":"OMEN_LOTUS_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"혹시…….","JPN":"もしかして……","ENG":"Are you...","TWN":"難道……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"오호……?","JPN":"ほお……？","ENG":"Oho...?","TWN":"喔喔……？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"실례가 안 된다면 코어를 좀 들여다봐도 될까?","JPN":"失礼じゃなければ、コアをちょっと見せてもらってもいいかな？","ENG":"If you don't mind, may I take a look at your core?","TWN":"如果不介意的話，我可以看看核心嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L50_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"아, 그, 기계 입장에선 알몸을 보여주는 것 같으려나?","JPN":"あっ、その……機械からすると裸を見せるようなことなのかな。","ENG":"Ah, from a machine's point of view, would that feel like showing your bare body?","TWN":"啊、這、對機械來說是不是像被看光一樣？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"괘, 괜찮아! 내 실력이라면 그런 느낌도 안 나게 감쪽같이 여닫을 수 있으니까!","JPN":"だ、大丈夫！　私の腕なら、そんな思いさせないぐらい綺麗に開閉できるから！","ENG":"I-it is fine! With my skill, I can open and close it so cleanly you won't even feel it!","TWN":"沒、沒關係！以我的實力，可以讓你完全沒有那種害羞的感覺！"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"}}}},{"id":"L6_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"……안타깝다는 말 취소.","JPN":"……可哀想だという発言は撤回する。","ENG":"...I take back what I said about feeling sorry.","TWN":"……我收回剛剛覺得你很可憐的話。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"선로전환기는 이미 괴물이 넘겨받아 운송을 시작했다.","JPN":"線路転換器はすでに化け物に引き渡され、輸送中だ。","ENG":"The Track Switcher has already been handed to the monster and transport has begun.","TWN":"線路轉換器已經交給怪物接手並開始運送了。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"그리고 선로전환기의 설계를 살펴보는 과정에서 문제점을 하나 발견했지.","JPN":"そして線路転換器の設計を確認する過程で、1つ問題点を発見した。","ENG":"Also, while reviewing the Track Switcher design, I found one problem.","TWN":"我在查看線路轉換器的設計時，發現了一個問題。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"무, 문제점이라고?","JPN":"も、問題点？","ENG":"A p-problem?","TWN":"問、問題？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"내 완벽한 설계에 그럼 오점이 존재할 리가 없는데?","JPN":"私の完璧な設計に、そんな汚点なんてあるわけない。","ENG":"There's no way my perfect design has a flaw.","TWN":"在我完美的設計下不可能有缺陷啊？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"너 같은 공학자들이 한 번씩 저지르는 치명적인 실수다.","JPN":"お前のような工学者が一度は必ず犯す、致命的なミスだ。","ENG":"It is the fatal mistake engineers like you make sooner or later.","TWN":"這是你這種工程師偶爾會犯下的致命錯誤。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EVOLVE_SCAVENGER_NULL_NULL","text":{"KOREA":"너무나 당연하다고 생각해 자기도 모르고 넘기는 것들 말이다.","JPN":"当たり前すぎると思い込み、見落としてしまう。","ENG":"The things you assume are so obvious that you do not even notice them.","TWN":"因為妳認為太理所當然了，才會自己都沒意識到。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"EVOLVE_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};